```typescript
interface Article {
  id: number;
  nom: string;
  prix: number;
  description?: string;
  stock: number;
  dateAjout?: Date;
}

// ArticleCreation : sans id et sans dateAjout, tous obligatoires
type ArticleCreation = Omit<Article, 'id' | 'dateAjout'>;
// ou Required<Omit<Article, 'id' | 'dateAjout'>> si on veut enforcer l'obligation
// mais ici description est déjà optionnelle dans l'original

// Version plus stricte où description devient obligatoire :
type ArticleCreationStrict = Required<Omit<Article, 'id' | 'dateAjout'>>;

// ArticleAffichage : seulement nom, prix et description
type ArticleAffichage = Pick<Article, 'nom' | 'prix' | 'description'>;

// ArticleModification : tous les champs optionnels
type ArticleModification = Partial<Article>;
```

Problèmes identifiés :
1. `config2` n'a pas de type explicite. L'objet contient `retries: null` mais `Config` attend `retries?: number`.
2. `Partial<Config>` accepte `null` pour `retries` alors que le type original n'accepte que `number | undefined`.
3. L'appel à `toFixed` sur `resultat.retries` est dangereux car `retries` pourrait être `null`.

Correction :
```typescript
interface Config {
  url: string;
  timeout: number;
  retries?: number;
  headers?: Record<string, string>;
}

// Utiliser NonNullable pour filtrer les valeurs null
type SafePartial<T> = {
  [P in keyof T]?: T[P] extends undefined ? T[P] : NonNullable<T[P]>;
};

function mergeConfig(base: Config, override: Partial<Config>): Config {
  return { ...base, ...override };
}

const config1: Config = { url: "https://api.example.com", timeout: 5000 };
const config2: Partial<Config> = { timeout: 10000, retries: 3 }; // pas de null

const resultat = mergeConfig(config1, config2);
// Vérification avant utilisation
if (resultat.retries !== undefined) {
  console.log(resultat.retries.toFixed(2));
}
```
Ou mieux : utiliser `Required` pour forcer toutes les propriétés :
```typescript
function mergeConfigStrict(base: Config, override: Partial<Config>): Required<Config> {
  return { ...base, ...override } as Required<Config>;
}
```

```typescript
interface Utilisateur {
  id: number;
  nomComplet: string;
  email: string;
  telephone: string;
  adresse?: string;
  dateInscription: Date;
  estActif: boolean;
  roles: ('admin' | 'user' | 'moderateur')[];
}

// 1. UtilisateurPublic : seulement les champs visibles publiquement
type UtilisateurPublic = Pick<Utilisateur, 'nomComplet' | 'email' | 'estActif'>;

// 2. UtilisateurCreation : sans id, sans dateInscription, roles optionnel
type UtilisateurCreation = Omit<Utilisateur, 'id' | 'dateInscription'> & {
  roles?: ('admin' | 'user' | 'moderateur')[];
};

// Version alternative avec Partial sur roles uniquement
// 3. UtilisateurModification : tous les champs optionnels SAUF id
type UtilisateurModification = Partial<Omit<Utilisateur, 'id'>> & { id: number };

// 4. Fonction de mise à jour simulée
const baseDeDonnees: Map<number, Utilisateur> = new Map();

function mettreAJourUtilisateur(
  id: number,
  modifications: UtilisateurModification
): Utilisateur | null {
  const utilisateurExistant = baseDeDonnees.get(id);

  if (!utilisateurExistant) {
    console.log(`Utilisateur avec l'id ${id} non trouvé.`);
    return null;
  }

  // Fusionner les modifications
  const utilisateurMisAJour: Utilisateur = {
    ...utilisateurExistant,
    ...modifications
  };

  baseDeDonnees.set(id, utilisateurMisAJour);
  console.log(`Utilisateur ${id} mis à jour avec succès.`);
  return utilisateurMisAJour;
}

// Création d'un utilisateur pour tester
const nouvelUtilisateur: UtilisateurCreation = {
  nomComplet: "Alice Ndi",
  email: "alice@example.com",
  telephone: "691234567",
  adresse: "Douala, Cameroun",
  estActif: true,
  roles: ['user']
};

const utilisateurComplet: Utilisateur = {
  id: 1,
  ...nouvelUtilisateur,
  dateInscription: new Date(),
  roles: nouvelUtilisateur.roles || ['user']
};

baseDeDonnees.set(1, utilisateurComplet);

// Test de mise à jour
const modifications: UtilisateurModification = {
  id: 1,
  nomComplet: "Alice Ndi-Mbarga",
  estActif: true,
  telephone: "698765432"
};

const resultat = mettreAJourUtilisateur(1, modifications);
console.log("Utilisateur après mise à jour :", resultat);

// Affichage public
const affichagePublic: UtilisateurPublic = {
  nomComplet: resultat!.nomComplet,
  email: resultat!.email,
  estActif: resultat!.estActif
};
console.log("Affichage public :", affichagePublic);
```
